WebLink.url:
{!REQUIRESCRIPT('/soap/ajax/47.0/connection.js')}
{!REQUIRESCRIPT('/soap/ajax/47.0/apex.js')}

if ('{!Interview__c.InterviewStatus__c}' == '公開中') {
　
var id = '{!Interview__c.Id}';

var result = sforce.apex.execute('SFTR_O_InterviewWebService', 'takeback', {itemId:id});

if(result == '成功'){
location.reload();
}else{
alert('取戻が失敗してしまった');
}

} else {
alert('この処理が実行できません！');
}
